#include <stdio.h>
#include <stdint.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int64_t N, X;
        scanf("%lld %lld", &N, &X);
        int64_t cycle = 3LL * X;
        int64_t ans = N / cycle;
        printf("%lld\n", ans);
    }
    return 0;
}

